/// 架构无关的内核入口。各平台 `_start`（在 khal）设好栈后跳到这里。
#[unsafe(no_mangle)]
pub extern "C" fn kunikos_main() -> ! {
    khal::kprintln!("\n[KunikOS] booting on {}", khal::ARCH);

    let mut v: Vec<u32> = Vec::new();
    for i in 0..8 {
        v.push(i * i);
    }
    khal::kprintln!("[KunikOS] heap ready: {:?}", v);

    khal::init_trap();
    khal::test_breakpoint();
    khal::kprintln!("[KunikOS] trap round-trip ok");

    khal::init_paging();
    let mut w: Vec<u8> = Vec::with_capacity(32);
    w.extend_from_slice(b"paged-heap-ok");
    khal::kprintln!(
        "[KunikOS] paging + frame alloc + dynamic map ok ({})",
        core::str::from_utf8(&w).unwrap()
    );

    khal::kprintln!("[KunikOS] boot pipeline ok");

    if !virtio_blk::init() {
        khal::kprintln!("[KunikOS] no virtio-blk device");
        khal::shutdown();
    }
    let fs = match ext4::Ext4::mount() {
        Some(f) => f,
        None => {
            khal::kprintln!("[KunikOS] ext4 mount failed");
            khal::shutdown();
        }
    };
    ext4::set_global(&fs);
    // 按盘上内容选测试集：libc-test / lua / ltp / basic。
    if let Some(elf) = fs.load("entry-static.exe") {
        run_libctest(&elf);
    } else if let Some(elf) = fs.load("lua") {
        run_lua(&elf);
    } else if fs.load("__ltp__").is_some() {
        run_ltp(&fs);
    } else {
        run_basic(&fs);
    }
    khal::shutdown();
}

/// LTP：遍历盘根目录，逐个跑 ELF 测试，按 oscomp 格式打 RUN/FAIL 标记。
fn run_ltp(fs: &ext4::Ext4) {
    khal::kprintln!("#### OS COMP TEST GROUP START ltp ####");
    for name in fs.list_root() {
        if name == "lost+found" || name == "__ltp__" || name.is_empty() {
            continue;
        }
        let elf = match fs.load(&name) {
            Some(e) if e.len() >= 4 && &e[0..4] == b"\x7fELF" => e,
            _ => continue,
        };
        khal::kprintln!("RUN LTP CASE {}", name);
        fs::reset();
        khal::reset_user_space();
        let (entry, sp) = khal::load_elf_args(&elf, &[&name]);
        let code = khal::run_user(entry, sp);
        khal::kprintln!("FAIL LTP CASE {} : {}", name, code);
    }
    khal::kprintln!("#### OS COMP TEST GROUP END ltp ####");
}

fn run_lua(elf: &[u8]) {
    const SCRIPTS: &[&str] = &[
        "date.lua",
        "file_io.lua",
        "max_min.lua",
        "random.lua",
        "remove.lua",
        "round_num.lua",
        "sin30.lua",
        "sort.lua",
        "strings.lua",
    ];
    khal::kprintln!("#### OS COMP TEST GROUP START lua ####");
    for s in SCRIPTS {
        fs::reset();
        khal::reset_user_space();
        let (entry, sp) = khal::load_elf_args(elf, &["lua", s]);
        let code = khal::run_user(entry, sp);
        khal::kprintln!("[lua] {} exit {}", s, code);
    }
    khal::kprintln!("#### OS COMP TEST GROUP END lua ####");
}

