//! 内核堆：静态区上的空闲链表分配器（首次适配 + 相邻块合并，支持回收）。
//! 单 hart 顺序执行，用 16 字节对齐的内嵌空闲块头（size, next）。
use core::alloc::{GlobalAlloc, Layout};
use core::cell::UnsafeCell;
use core::sync::atomic::{AtomicBool, Ordering};

const HEAP_SIZE: usize = 0x400_0000; // 64 MiB（容纳测试 ftruncate 的大文件 + ELF 加载）
const MIN: usize = 16; // 块粒度，满足 align<=16 的全部内核分配

#[repr(align(16))]
struct HeapMem(UnsafeCell<[u8; HEAP_SIZE]>);
unsafe impl Sync for HeapMem {}
static HEAP: HeapMem = HeapMem(UnsafeCell::new([0; HEAP_SIZE]));

// 空闲块头放在块起始：[size: usize][next: usize(地址，0=末尾)]
fn rd(addr: usize, off: usize) -> usize {
    unsafe { *((addr + off) as *const usize) }
}
fn wr(addr: usize, off: usize, val: usize) {
    unsafe { *((addr + off) as *mut usize) = val };
}
fn bsize(b: usize) -> usize {
    rd(b, 0)
}
fn bnext(b: usize) -> usize {
    rd(b, 8)
}

fn align_up(x: usize, a: usize) -> usize {
    (x + a - 1) & !(a - 1)
}

struct FreeList {
    lock: AtomicBool,
    head: UnsafeCell<usize>, // 首个空闲块地址，0=空
    init: UnsafeCell<bool>,
}
unsafe impl Sync for FreeList {}

impl FreeList {
    fn ensure_init(&self) {
        unsafe {
            if !*self.init.get() {
                let base = HEAP.0.get() as usize;
                wr(base, 0, HEAP_SIZE);
                wr(base, 8, 0);
                *self.head.get() = base;
                *self.init.get() = true;
            }
        }
    }

    // 把 [addr, addr+sz) 按地址序插回空闲链表，合并相邻块。
    fn insert(&self, addr: usize, sz: usize) {
        unsafe {
            let head = self.head.get();
            let mut prev = 0usize;
            let mut cur = *head;
            while cur != 0 && cur < addr {
                prev = cur;
                cur = bnext(cur);
            }
            // 与后块合并
            let mut size = sz;
            let mut next = cur;
            if cur != 0 && addr + size == cur {
                size += bsize(cur);
                next = bnext(cur);
            }
            wr(addr, 0, size);
            wr(addr, 8, next);
            // 与前块合并
            if prev != 0 && prev + bsize(prev) == addr {
                wr(prev, 0, bsize(prev) + size);
                wr(prev, 8, next);
            } else if prev != 0 {
                wr(prev, 8, addr);
            } else {
                *head = addr;
            }
        }
    }
}

unsafe impl GlobalAlloc for FreeList {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        // 单 hart：自旋锁仅为满足并发安全形态
        while self
            .lock
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            core::hint::spin_loop();
        }
        self.ensure_init();
        let need = align_up(layout.size().max(1), MIN);
        let head = self.head.get();
        let mut prev = 0usize;
        let mut cur = unsafe { *head };
        let mut ret = core::ptr::null_mut();
        while cur != 0 {
            let bs = bsize(cur);
            if bs >= need {
                let rem = bs - need;
                let new = if rem >= MIN {
                    wr(cur + need, 0, rem);
                    wr(cur + need, 8, bnext(cur));
                    cur + need
                } else {
                    bnext(cur)
                };
                if prev == 0 {
                    unsafe { *head = new };
                } else {
                    wr(prev, 8, new);
                }
                ret = cur as *mut u8;
                break;
            }
            prev = cur;
            cur = bnext(cur);
        }
        self.lock.store(false, Ordering::Release);
        ret
    }

    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        if ptr.is_null() {
            return;
        }
        while self
            .lock
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            core::hint::spin_loop();
        }
        let sz = align_up(layout.size().max(1), MIN);
        self.insert(ptr as usize, sz);
        self.lock.store(false, Ordering::Release);
    }
}

#[global_allocator]
static ALLOC: FreeList = FreeList {
    lock: AtomicBool::new(false),
    head: UnsafeCell::new(0),
    init: UnsafeCell::new(false),
};

use core::panic::PanicInfo;

#[panic_handler]
fn panic(info: &PanicInfo) -> ! {
    khal::kprintln!("\n[KunikOS] kernel panic: {}", info);
    khal::shutdown();
}

//! 系统调用分发（架构无关，语义对齐 Linux）。
//! khal 的 trap 入口解出 (号, 参数) 后调用 kunikos_syscall，返回值写回 a0。

use khal::console_putchar;

#[unsafe(no_mangle)]
pub extern "C" fn kunikos_syscall(
    num: usize,
    a0: usize,
    a1: usize,
    a2: usize,
    a3: usize,
    a4: usize,
    _a5: usize,
) -> isize {
    match num {
        64 => sys_write(a0, a1, a2),
        93 | 94 => {
            khal::exit_user(a0);
        }
        96 => 1,                            // set_tid_address -> tid
        172 => unsafe { CUR_PID as isize }, // getpid
        178 => unsafe { CUR_PID as isize }, // gettid
        174 | 175 => 0,                     // getuid / geteuid
        176 | 177 => 0,                     // getgid / getegid
        29 => 0,                            // ioctl: 暂作 no-op
        17 => crate::fs::getcwd(a0, a1),
        101 => sys_nanosleep(a0),
        115 => sys_nanosleep(a2), // clock_nanosleep(clockid, flags, req, rem)
        124 => 0,                 // sched_yield
        153 => sys_times(a0),
        160 => sys_uname(a0),
        169 => sys_gettimeofday(a0),
        173 => unsafe { CUR_PPID as isize }, // getppid
        214 => khal::user_brk(a0) as isize,
        215 => 0, // munmap
        222 => sys_mmap(a1, a3, a4),
        226 => 0, // mprotect
        56 => crate::fs::openat(&user_cstr(a1), a2),
        57 => crate::fs::close(a0),
        61 => crate::fs::getdents64(a0, a1, a2),
        63 => crate::fs::read(a0, a1, a2),
        80 => crate::fs::fstat(a0, a1),
        23 => crate::fs::dup(a0),
        24 => crate::fs::dup3(a0, a1),
        34 => crate::fs::mkdir(&user_cstr(a1)),
        35 => crate::fs::unlink(&user_cstr(a1)),
        48 => sys_faccessat(a1), // faccessat：存在性检查（root 有全权限）
        52 => 0,                 // fchmod
        53 => 0,                 // fchmodat
        54 => 0,                 // fchownat
        55 => 0,                 // fchown
        33 => 0,                 // mknodat
        36 => 0,                 // symlinkat
        37 => 0,                 // linkat
        45 => 0,                 // truncate
        90 | 91 => 0,            // capget / capset
        133 => -4,               // rt_sigsuspend -> EINTR（无信号投递，避免阻塞）
        143 | 144 | 145 | 146 | 147 | 149 | 151 | 152 => 0, // set{re,fs,}{u,g}id / setres{u,g}id（root 恒成功）
        148 | 150 => sys_getres(a0, a1, a2),                // getresuid / getresgid
        242 => crate::net::accept(a0),                      // accept4
        49 => crate::fs::chdir(&user_cstr(a0)),             // chdir
        39 => 0,                                            // umount2
        40 => 0,                                            // mount
        59 => crate::fs::pipe2(a0),
        73 => sys_ppoll(a0, a1),                 // ppoll：同步内核标 fd 就绪
        83 => 0,                                 // fdatasync
        10 => -61,                               // fgetxattr -> ENODATA
        198 => crate::net::socket(a1),           // socket(domain, type, proto)
        200 => crate::net::bind(a0, a1),         // bind(fd, addr, len)
        201 => crate::net::listen(a0),           // listen(fd, backlog)
        202 => crate::net::accept(a0),           // accept(fd, addr, len)
        203 => crate::net::connect(a1),          // connect(fd, addr, len)
        204 => crate::net::getsockname(a0, a1),  // getsockname(fd, addr, len)
        206 => crate::net::sendto(a1, a2, a4),   // sendto(fd, buf, len, flags, addr, len)
        207 => crate::net::recvfrom(a0, a1, a2), // recvfrom(fd, buf, len, flags, addr, len)
        208 => 0,                                // setsockopt
        98 => sys_futex(a0, a1, a2),
        62 => crate::fs::lseek(a0, a1 as isize, a2),
        65 => sys_readv(a0, a1, a2),
        66 => sys_writev(a0, a1, a2),
        46 => crate::fs::ftruncate(a0, a1), // ftruncate
        67 => crate::fs::pread(a0, a1, a2, a3),
        68 => crate::fs::pwrite(a0, a1, a2, a3),
        25 => sys_fcntl(a0, a1, a2),
        43 | 44 => sys_statfs(a1), // statfs(path,buf) / fstatfs(fd,buf)
        163 => sys_prlimit(a0, 0, a1), // getrlimit(res, rlim)
        164 => sys_prlimit(a0, a1, 0), // setrlimit(res, rlim)
        261 => sys_prlimit(a1, a2, a3), // prlimit64(pid, res, new, old)
        88 => {
            // utimensat(dirfd, path, times, flags)；path=NULL 即 futimens(fd=dirfd)
            if a1 == 0 {
                crate::fs::utimens_fd(a0, a2)
            } else {
                crate::fs::utimens(&user_cstr(a1), a2)
            }
        }
        89 => 0,                                         // utime（老接口，忽略）
        79 => crate::fs::stat_path(&user_cstr(a1), a2),  // fstatat(dirfd, path, buf, flags)
        291 => crate::fs::statx(a0, &user_cstr(a1), a4), // statx(dirfd, path, flags, mask, buf)
        113 => sys_clock_gettime(a1),
        122 => 0, // sched_setaffinity
        123 => sys_sched_getaffinity(a1, a2),
        99 => 0,                    // set_robust_list
        233 => 0,                   // madvise
        228..=231 => 0,             // mlock / munlock / mlockall / munlockall
        159 => 0,                   // setgroups
        232 => sys_mincore(a1, a2), // mincore
        165 => sys_getrusage(a1),   // getrusage
        179 => sys_sysinfo(a0),     // sysinfo
        278 => sys_getrandom(a0, a1),
        47 => 0, // fdatasync
        82 => 0, // fsync
        166 => sys_umask(a0),
        78 => sys_readlinkat(&user_cstr(a1), a2, a3), // readlinkat(dirfd, path, buf, sz)
        103 => 0,                                     // setitimer
        129 => 0,                                     // kill
        130 => 0,                                     // tkill
        131 => 0,                                     // tgkill
        154 => 0,                                     // setpgid
        155 => 1,                                     // getpgid
        157 => 0,                                     // setsid
        227 => 0,                                     // msync
        134 => 0,                                     // rt_sigaction
        135 => sys_rt_sigprocmask(a0, a1, a2),
        220 => sys_clone(a0, a1, a3, a4),
        221 => sys_execve(a0),
        260 => sys_wait4(a0, a1),
        _ => {
            khal::kprintln!("[sys] unhandled {}", num);
            -38 // -ENOSYS
        }
    }
}

// 进程模型：fork 同步跑完子进程，记录退出码为僵尸，wait4 回收。
static mut NEXT_PID: usize = 3;
static mut ZOMBIES: [(usize, usize); 32] = [(0, 0); 32];
static mut NZOMBIE: usize = 0;
// 当前进程 pid / 父 pid（主程序 pid=2，父=1；fork 子进程期间临时切换）。
static mut CUR_PID: usize = 2;
static mut CUR_PPID: usize = 1;

/// 每个程序启动前重置进程态（与 fs::reset 同步调用）。
pub fn reset_pids() {
    unsafe {
        NEXT_PID = 3;
        NZOMBIE = 0;
        CUR_PID = 2;
        CUR_PPID = 1;
        SIGMASK = 0;
        UMASK = 0o22;
    }
}

/// clone：CLONE_VM(0x100) 为线程（共享地址空间），否则为 fork（复制 fd 表 + 快照还原）。
/// 同步跑完子进程/线程。CHILD_SETTID/CLEARTID 写/清 *ctid，配合 futex 让 join 完成。
fn sys_clone(flags: usize, new_sp: usize, tls: usize, ctid: usize) -> isize {
    let pid = unsafe {
        let p = NEXT_PID;
        NEXT_PID += 1;
        p
    };
