    // 仅 CLONE_SETTLS 时才用 tls（fork 只传 2 个参数，a3/a4 是残留垃圾）。
    let tls = if flags & 0x80000 != 0 { tls } else { 0 };
    let ctid = if flags & 0x0120_0000 != 0 { ctid } else { 0 };
    if !is_thread {
        crate::fs::fork_push();
    }
    if flags & 0x0100_0000 != 0 && ctid != 0 {
        // CLONE_CHILD_SETTID
        unsafe { (ctid as *mut u32).write_volatile(pid as u32) };
    }
    // 子进程运行期间切换当前 pid/ppid（getpid/getppid 据此返回）。
    let (saved_pid, saved_ppid) = unsafe { (CUR_PID, CUR_PPID) };
    unsafe {
        CUR_PPID = CUR_PID;
        CUR_PID = pid;
    }
    let code = khal::spawn_child(new_sp, tls, is_thread);
    unsafe {
        CUR_PID = saved_pid;
        CUR_PPID = saved_ppid;
    }
