//! 进程 fd 表 + 内存文件存储：磁盘文件首次打开从 ext4 载入内存，O_CREAT 新建空文件，
//! 写入回写到内存节点，close/reopen 可读回。单进程顺序执行，每程序 reset()。
use crate::ext4;
use alloc::string::String;
use alloc::vec::Vec;

struct Node {
    name: String,
    data: Vec<u8>,
    dir: bool,
    names: Vec<String>,
    atime: u64, // 秒
    mtime: u64,
}

impl Node {
    fn file(name: &str, data: Vec<u8>) -> Node {
        Node {
            name: String::from(name),
            data,
            dir: false,
            names: Vec::new(),
            atime: 0,
            mtime: 0,
        }
    }
    fn dir(name: &str, names: Vec<String>) -> Node {
        Node {
            name: String::from(name),
            data: Vec::new(),
            dir: true,
            names,
            atime: 0,
            mtime: 0,
        }
    }
}

static mut FILES: Vec<Node> = Vec::new();

fn files() -> &'static mut Vec<Node> {
    unsafe { &mut *(&raw mut FILES) }
}

#[derive(Clone)]
enum Fd {
    Console,
    File { idx: usize, pos: usize },
    PipeR(usize),
    PipeW(usize),
    Null,          // /dev/null：读返回 EOF，写丢弃
    Zero,          // /dev/zero：读返回全 0，写丢弃
    Socket(usize), // 下标进 net::SOCKETS
}

/// 安装一个 socket（net 用），返回新 fd。
pub fn install_socket(sidx: usize) -> isize {
    match alloc_fd() {
        Some(fd) => {
            fds()[fd] = Some(Fd::Socket(sidx));
            fd as isize
        }
        None => -24,
    }
}

/// 取 fd 对应的 socket 下标。
pub fn socket_of(fd: usize) -> Option<usize> {
    if fd < MAXFD
        && let Some(Fd::Socket(i)) = &fds()[fd]
    {
        Some(*i)
    } else {
        None
    }
}

const MAXFD: usize = 64;
static mut FDS: [Option<Fd>; MAXFD] = [const { None }; MAXFD];

fn fds() -> &'static mut [Option<Fd>; MAXFD] {
    unsafe { &mut *(&raw mut FDS) }
}

// 管道缓冲：单向字节流，读端按 rpos 推进，读空即 EOF（顺序执行下写端先写完）。
struct PipeBuf {
    buf: Vec<u8>,
    rpos: usize,
}

static mut PIPES: Vec<PipeBuf> = Vec::new();

fn pipes() -> &'static mut Vec<PipeBuf> {
    unsafe { &mut *(&raw mut PIPES) }
}

// fork 时父进程 fd 表快照栈：子进程在活表上改动，结束后还原父表。
static mut FD_SAVE: Vec<[Option<Fd>; MAXFD]> = Vec::new();

/// fork：保存父进程 fd 表快照，子进程在活表上独立改动。
pub fn fork_push() {
    let snap: [Option<Fd>; MAXFD] = core::array::from_fn(|i| fds()[i].clone());
    unsafe { (&mut *(&raw mut FD_SAVE)).push(snap) };
}

/// fork 子进程结束：丢弃子进程改动，还原父进程 fd 表。
pub fn fork_pop() {
    if let Some(snap) = unsafe { (&mut *(&raw mut FD_SAVE)).pop() } {
        *fds() = snap;
    }
}

/// pipe2(fd[2])：建一条管道，写 fd[0]=读端、fd[1]=写端到用户数组。
pub fn pipe2(fdarray: usize) -> isize {
    pipes().push(PipeBuf {
        buf: Vec::new(),
        rpos: 0,
    });
    let pidx = pipes().len() - 1;
    let rfd = match alloc_fd() {
        Some(f) => f,
        None => return -24,
    };
    fds()[rfd] = Some(Fd::PipeR(pidx));
    let wfd = match alloc_fd() {
        Some(f) => f,
        None => return -24,
    };
    fds()[wfd] = Some(Fd::PipeW(pidx));
    unsafe {
        (fdarray as *mut i32).write_volatile(rfd as i32);
        ((fdarray + 4) as *mut i32).write_volatile(wfd as i32);
    }
    0
}

/// 程序启动前重置：fd 0/1/2 = console，清空内存文件。
pub fn reset() {
    let t = fds();
    for f in t.iter_mut() {
        *f = None;
    }
    t[0] = Some(Fd::Console);
    t[1] = Some(Fd::Console);
    t[2] = Some(Fd::Console);
    files().clear();
    set_nofile(MAXFD);
    *cwd() = String::from("/");
    crate::net::reset();
    crate::syscall::reset_pids();
}

static mut CWD: String = String::new();
fn cwd() -> &'static mut String {
    unsafe { &mut *(&raw mut CWD) }
}

/// chdir：解析为绝对路径并规范化（处理 . / ..），目标须为已存在目录或根，更新 cwd。
pub fn chdir(path: &str) -> isize {
    let raw = if path.starts_with('/') {
        String::from(path)
    } else {
        let mut s = cwd().clone();
        if !s.ends_with('/') {
            s.push('/');
        }
        s.push_str(path);
        s
    };
    let mut comps: Vec<&str> = Vec::new();
    for c in raw.split('/') {
        match c {
            "" | "." => {}
            ".." => {
                comps.pop();
            }
            _ => comps.push(c),
        }
    }
    // 目录名按全路径（去前导 /）存储，故比对规范化后的全路径，根目录恒存在。
    let full = comps.join("/");
    let exists = comps.is_empty() || files().iter().any(|n| n.name == full && n.dir);
    if !exists {
        return -2; // ENOENT
    }
    let mut abs = String::from("/");
    abs.push_str(&full);
    *cwd() = abs;
    0
}

/// getcwd：把当前工作目录写入 buf。
pub fn getcwd(buf: usize, size: usize) -> isize {
    let s = cwd().clone();
    let b = s.as_bytes();
    if buf == 0 || size < b.len() + 1 {
        return -34; // ERANGE
    }
    unsafe {
        for (i, &c) in b.iter().enumerate() {
            (buf as *mut u8).add(i).write_volatile(c);
        }
        (buf as *mut u8).add(b.len()).write_volatile(0);
    }
    buf as isize
}

// RLIMIT_NOFILE：可打开的最大 fd 数（受 setrlimit 调整，封顶 MAXFD）。
static mut RLIM_NOFILE: usize = MAXFD;

pub fn get_nofile() -> usize {
    unsafe { RLIM_NOFILE }
}
pub fn set_nofile(n: usize) {
    unsafe { RLIM_NOFILE = core::cmp::min(n, MAXFD) };
}

fn alloc_fd() -> Option<usize> {
    let lim = unsafe { RLIM_NOFILE.min(MAXFD) };
    fds()[..lim].iter().position(|f| f.is_none())
}

/// mkdirat：在内存建一个目录节点。重复创建视为成功。
pub fn mkdir(path: &str) -> isize {
    let name = path.trim_start_matches("./").trim_start_matches('/');
    if files().iter().any(|n| n.name == name) {
        return 0;
    }
    files().push(Node::dir(name, Vec::new()));
    0
}

/// unlinkat：清空内存节点名字，使再次 open（无 O_CREAT）找不到。
pub fn unlink(path: &str) -> isize {
    let name = path.trim_start_matches("./").trim_start_matches('/');
    if let Some(i) = files().iter().position(|n| n.name == name) {
        files()[i].name.clear();
    }
    0
}

// 找/建内存节点（磁盘文件首次访问从 ext4 载入），返回 idx。
fn node_idx(name: &str, create: bool) -> Option<usize> {
    if let Some(i) = files().iter().position(|n| n.name == name) {
        return Some(i);
    }
    if let Some(data) = ext4::global().load(name) {
        files().push(Node::file(name, data));
        return Some(files().len() - 1);
    }
    if create {
        files().push(Node::file(name, Vec::new()));
        return Some(files().len() - 1);
    }
    None
}

pub fn is_console(fd: usize) -> bool {
    fd < MAXFD && matches!(fds()[fd], Some(Fd::Console))
}

// 合成 /proc、/sys 等只读伪文件（LTP tst 框架启动要读）。
/// /proc/<pid>/X 归一为 /proc/self/X（数字 pid 段映射到当前进程视图）。
fn normalize_proc(name: &str) -> Option<String> {
    let rest = name.strip_prefix("proc/")?;
    let slash = rest.find('/')?;
    let (pid, tail) = rest.split_at(slash);
    if !pid.is_empty() && pid != "self" && pid.bytes().all(|b| b.is_ascii_digit()) {
        Some(alloc::format!("proc/self{tail}"))
    } else {
        None
    }
}

