//! 最小 ext4 只读：超级块 + inode(extent, depth 0) + 根目录项 + 按名读文件。
//! 仅支持 4096 块大小（赛事与本地镜像默认）。块经 virtio-blk 读取。
use crate::virtio_blk;
use alloc::string::String;
use alloc::vec::Vec;

const BS: usize = 4096;

static mut FS_PTR: *const Ext4 = core::ptr::null();

/// 记录全局已挂载的文件系统（供 syscall 层访问）。
pub fn set_global(fs: &Ext4) {
    unsafe { FS_PTR = fs as *const Ext4 };
}
pub fn global() -> &'static Ext4 {
    unsafe { &*FS_PTR }
}

pub struct Ext4 {
    inode_size: usize,
    inodes_per_group: u32,
    desc_size: usize,
    bgd: Vec<u8>, // 块组描述符表，挂载时读一次缓存（避免每次读 inode 重复读盘）
}

fn rd16(b: &[u8], o: usize) -> u16 {
    u16::from_le_bytes([b[o], b[o + 1]])
}
fn rd32(b: &[u8], o: usize) -> u32 {
    u32::from_le_bytes([b[o], b[o + 1], b[o + 2], b[o + 3]])
}

fn read_block(blk: u64, buf: &mut [u8]) -> bool {
    virtio_blk::read(blk * (BS as u64 / 512), buf)
}

impl Ext4 {
    pub fn mount() -> Option<Ext4> {
        let mut b = [0u8; BS];
        if !read_block(0, &mut b) {
            return None;
        }
        let sb = &b[1024..];
        if rd16(sb, 0x38) != 0xef53 {
            return None;
        }
        if (1024usize << rd32(sb, 0x18)) != BS {
            return None;
        }
        let mut desc_size = rd16(sb, 0xfe) as usize;
        if desc_size < 32 {
            desc_size = 32;
        }
        let inode_size = rd16(sb, 0x58) as usize;
        let inodes_per_group = rd32(sb, 0x28);
        let first_data_block = rd32(sb, 0x14);
        let num_groups = rd32(sb, 0x0).div_ceil(inodes_per_group) as usize;
        // 缓存块组描述符表（紧随超级块块，跨 ceil(组数*描述符/块) 块）。
        let bgd_blocks = (num_groups * desc_size).div_ceil(BS);
        let mut bgd = alloc::vec![0u8; bgd_blocks * BS];
        for i in 0..bgd_blocks {
            let mut blk = [0u8; BS];
            read_block((first_data_block + 1 + i as u32) as u64, &mut blk);
            bgd[i * BS..(i + 1) * BS].copy_from_slice(&blk);
        }
        Some(Ext4 {
            inode_size,
            inodes_per_group,
            desc_size,
            bgd,
        })
    }

    fn inode_table_block(&self, group: u32) -> u64 {
        let off = group as usize * self.desc_size;
        let lo = rd32(&self.bgd, off + 0x8) as u64;
        let hi = if self.desc_size >= 64 {
            rd32(&self.bgd, off + 0x28) as u64
        } else {
            0
        };
        (hi << 32) | lo
    }

    fn read_inode(&self, ino: u32) -> Vec<u8> {
        let group = (ino - 1) / self.inodes_per_group;
        let idx = ((ino - 1) % self.inodes_per_group) as usize;
        let byte = self.inode_table_block(group) * BS as u64 + (idx * self.inode_size) as u64;
        let mut b = [0u8; BS];
        read_block(byte / BS as u64, &mut b);
        let within = (byte % BS as u64) as usize;
        b[within..within + self.inode_size].to_vec()
    }

    // 按 extent（depth 0）收集 (逻辑起块, 物理起块, 块数) 连续段。稀疏空洞不在列表里。
    /// 遍历 extent 树（支持多级：depth>0 的索引节点指向磁盘上的 extent 叶块）。
    /// 大文件/大目录用索引树，仅读内联 extent 会漏块。
    fn extent_runs(&self, inode: &[u8]) -> Vec<(u32, u64, u32)> {
        let mut out = Vec::new();
        // 待处理节点栈：内联头（inode i_block）或磁盘 extent 块。
        let mut stack: Vec<Vec<u8>> = alloc::vec![inode[0x28..0x28 + 60].to_vec()];
        while let Some(node) = stack.pop() {
            if rd16(&node, 0) != 0xf30a {
                continue; // extent 头魔数不符
            }
            let entries = rd16(&node, 2) as usize;
            let depth = rd16(&node, 6);
            for e in 0..entries {
                let x = &node[12 + e * 12..];
                if depth == 0 {
                    // ext4_extent 叶：ee_block / ee_len / ee_start_hi / ee_start_lo
                    let lblk = rd32(x, 0);
                    let len = rd16(x, 4) as u32;
                    let phys = ((rd16(x, 6) as u64) << 32) | rd32(x, 8) as u64;
                    out.push((lblk, phys, len));
                } else {
                    // ext4_extent_idx：ei_leaf_lo(4) | ei_leaf_hi(8) → 下级 extent 块
                    let child = (rd32(x, 4) as u64) | ((rd16(x, 8) as u64) << 32);
                    let mut blk = [0u8; BS];
                    read_block(child, &mut blk);
                    stack.push(blk.to_vec());
                }
            }
        }
        out
    }

    // 逐块视图（目录扫描用，连续段展开成单块）。
    fn extents(&self, inode: &[u8]) -> Vec<(u32, u64)> {
        let mut out = Vec::new();
        for (lblk, phys, run) in self.extent_runs(inode) {
            for i in 0..run {
                out.push((lblk + i, phys + i as u64));
            }
        }
        out
    }

    fn read_file(&self, ino: u32) -> Vec<u8> {
        let inode = self.read_inode(ino);
        let size = rd32(&inode, 0x4) as usize; // i_size_lo
        // 按逻辑块号铺放，空洞留零（稀疏文件正确性关键）。
        let mut data = alloc::vec![0u8; size.div_ceil(BS) * BS];
        // 连续物理块每请求批量读（最多 DATA_MAX），把 1 MiB ELF 的 256 次往返压到 ~16 次。
        const PER: u32 = (virtio_blk::DATA_MAX / BS) as u32;
        for (lblk, phys, run) in self.extent_runs(&inode) {
            let mut done = 0u32;
            while done < run {
                let cnt = core::cmp::min(run - done, PER);
                let off = (lblk + done) as usize * BS;
                let bytes = cnt as usize * BS;
                if off + bytes <= data.len() {
                    let sector = (phys + done as u64) * (BS as u64 / 512);
                    virtio_blk::read(sector, &mut data[off..off + bytes]);
                }
                done += cnt;
            }
        }
        data.truncate(size);
        data
    }

    /// 在根目录（inode 2）按名查 inode 号。
    pub fn lookup_root(&self, name: &str) -> Option<u32> {
        let inode = self.read_inode(2);
        let mut b = [0u8; BS];
        for (_lblk, phys) in self.extents(&inode) {
            read_block(phys, &mut b);
            let mut off = 0;
            while off + 8 <= BS {
                let ino = rd32(&b, off);
                let rec = rd16(&b, off + 4) as usize;
                let nlen = b[off + 6] as usize;
                if rec == 0 {
                    break;
                }
                if ino != 0 && nlen == name.len() && &b[off + 8..off + 8 + nlen] == name.as_bytes()
                {
                    return Some(ino);
                }
                off += rec;
            }
        }
        None
    }

    /// 读根目录下名为 name 的文件全部内容。
    pub fn load(&self, name: &str) -> Option<Vec<u8>> {
        Some(self.read_file(self.lookup_root(name)?))
    }

    /// 列举根目录下所有名字（用于 getdents）。
    pub fn list_root(&self) -> Vec<String> {
        let inode = self.read_inode(2);
        let mut out = Vec::new();
        let mut b = [0u8; BS];
        for (_lblk, phys) in self.extents(&inode) {
            read_block(phys, &mut b);
            let mut off = 0;
            while off + 8 <= BS {
                let ino = rd32(&b, off);
                let rec = rd16(&b, off + 4) as usize;
                let nlen = b[off + 6] as usize;
                if rec == 0 {
                    break;
                }
                if ino != 0
                    && nlen > 0
                    && let Ok(s) = core::str::from_utf8(&b[off + 8..off + 8 + nlen])
                {
                    out.push(String::from(s));
                }
                off += rec;
            }
        }
        out
    }
}

//! 最小 virtio-blk 驱动：探测 + 读扇区。split virtqueue 三环放在一个连续页对齐结构里
//! （desc@0 / avail@256 / used@4096）。恒等映射下内核 VA = PA，故 ring/缓冲地址即设备
//! 可用的物理地址，无需翻译或弹跳缓冲。
//!
//! 传输层按架构分流：rv64 走 virtio-mmio（0x10001000 槽位扫描）；la64 走 virtio-pci
//! （ECAM 枚举 + BAR4 现代能力）。队列布局与 `read()` 主体两架构共用，仅 init/notify 不同。
use core::sync::atomic::{Ordering, fence};

const S_ACK: u8 = 1;
const S_DRIVER: u8 = 2;
const S_DRIVER_OK: u8 = 4;
const S_FEATURES_OK: u8 = 8;

const QSIZE: usize = 16;
const F_NEXT: u16 = 1;
const F_WRITE: u16 = 2;
const SECTOR: usize = 512;
pub const DATA_MAX: usize = 0x10000; // 64 KiB/请求：连续块批量读，减少 virtio 往返

#[repr(C)]
#[derive(Clone, Copy)]
struct Desc {
    addr: u64,
    len: u32,
    flags: u16,
    next: u16,
}
#[repr(C, align(2))]
struct Avail {
    flags: u16,
    idx: u16,
    ring: [u16; QSIZE],
    used_event: u16,
}
#[repr(C)]
#[derive(Clone, Copy)]
struct UsedElem {
    id: u32,
    len: u32,
}
#[repr(C, align(4))]
struct Used {
    flags: u16,
    idx: u16,
    ring: [UsedElem; QSIZE],
    avail_event: u16,
}

// avail 大小 = 2+2+2*QSIZE+2；used 须落在 QueueAlign(4096) 对齐处。
#[repr(C, align(4096))]
struct Queue {
    desc: [Desc; QSIZE],
    avail: Avail,
    _pad: [u8; 4096 - QSIZE * 16 - (6 + 2 * QSIZE)],
    used: Used,
}

#[repr(C)]
struct BlkReq {
    kind: u32,
    reserved: u32,
    sector: u64,
}

static mut QUEUE: Queue = Queue {
    desc: [Desc {
        addr: 0,
        len: 0,
        flags: 0,
        next: 0,
    }; QSIZE],
    avail: Avail {
        flags: 0,
        idx: 0,
        ring: [0; QSIZE],
        used_event: 0,
    },
    _pad: [0; 4096 - QSIZE * 16 - (6 + 2 * QSIZE)],
    used: Used {
        flags: 0,
        idx: 0,
        ring: [UsedElem { id: 0, len: 0 }; QSIZE],
        avail_event: 0,
    },
};
static mut REQ: BlkReq = BlkReq {
    kind: 0,
    reserved: 0,
    sector: 0,
};
static mut STATUS_BYTE: u8 = 0xff;

/// 从 sector 起读 buf.len() 字节（512 的倍数）。设备直接 DMA 进 buf——恒等映射下
/// 内核 VA = PA，省去经静态缓冲的中转拷贝（批量读 ELF 的主要开销）。返回是否成功。
pub fn read(sector: u64, buf: &mut [u8]) -> bool {
    let len = buf.len();
    if len == 0 || !len.is_multiple_of(SECTOR) {
        return false;
    }
    let q = &raw mut QUEUE;
    let req = &raw mut REQ;
    let stat = &raw mut STATUS_BYTE;
    unsafe {
        (*req).kind = 0; // VIRTIO_BLK_T_IN（读）
        (*req).reserved = 0;
        (*req).sector = sector;
        *stat = 0xff;
        (*q).desc[0] = Desc {
            addr: req as u64,
            len: 16,
            flags: F_NEXT,
            next: 1,
        };
        (*q).desc[1] = Desc {
            addr: buf.as_mut_ptr() as u64, // 直接 DMA 进目标
            len: len as u32,
            flags: F_NEXT | F_WRITE,
            next: 2,
        };
        (*q).desc[2] = Desc {
            addr: stat as u64,
            len: 1,
            flags: F_WRITE,
            next: 0,
        };
        let used_old = core::ptr::read_volatile(core::ptr::addr_of!((*q).used.idx));
        let ai = (*q).avail.idx;
        (*q).avail.ring[(ai as usize) % QSIZE] = 0;
        fence(Ordering::SeqCst);
        (*q).avail.idx = ai.wrapping_add(1);
        fence(Ordering::SeqCst);
        notify();
        let mut spins = 0u64;
        while core::ptr::read_volatile(core::ptr::addr_of!((*q).used.idx)) == used_old {
            fence(Ordering::SeqCst);
            spins += 1;
            if spins > 200_000_000 {
                return false;
            }
        }
        if *stat != 0 {
            return false;
        }
    }
    true
}

// ===== rv64：virtio-mmio 传输 =====
#[cfg(target_arch = "riscv64")]
mod transport {
    use super::*;

    const MMIO_BASE: usize = 0x1000_1000;
    const MMIO_STRIDE: usize = 0x1000;
    const MMIO_SLOTS: usize = 8;

    const R_MAGIC: usize = 0x000;
    const R_VERSION: usize = 0x004;
    const R_DEVICE_ID: usize = 0x008;
    const R_HOST_FEAT: usize = 0x010;
    const R_HOST_FEAT_SEL: usize = 0x014;
    const R_GUEST_FEAT: usize = 0x020;
    const R_GUEST_FEAT_SEL: usize = 0x024;
    const R_GUEST_PAGE_SIZE: usize = 0x028;
    const R_QUEUE_SEL: usize = 0x030;
    const R_QUEUE_NUM_MAX: usize = 0x034;
    const R_QUEUE_NUM: usize = 0x038;
    const R_QUEUE_ALIGN: usize = 0x03c;
    const R_QUEUE_PFN: usize = 0x040;
    const R_QUEUE_READY: usize = 0x044;
    const R_QUEUE_NOTIFY: usize = 0x050;
    const R_STATUS: usize = 0x070;
    const R_DESC_LOW: usize = 0x080;
    const R_DESC_HIGH: usize = 0x084;
    const R_DRIVER_LOW: usize = 0x090;
    const R_DRIVER_HIGH: usize = 0x094;
    const R_DEVICE_LOW: usize = 0x0a0;
    const R_DEVICE_HIGH: usize = 0x0a4;

    static mut BLK_BASE: usize = 0;

    fn r(base: usize, off: usize) -> u32 {
        unsafe { ((base + off) as *const u32).read_volatile() }
    }
    fn w(base: usize, off: usize, v: u32) {
        unsafe { ((base + off) as *mut u32).write_volatile(v) };
    }

    /// 扫描 MMIO 槽位，初始化第一个 virtio-blk 设备。
    pub fn init() -> bool {
        for i in 0..MMIO_SLOTS {
            let base = MMIO_BASE + i * MMIO_STRIDE;
            if r(base, R_MAGIC) != 0x7472_6976 || r(base, R_DEVICE_ID) != 2 {
                continue;
            }
            setup(base, r(base, R_VERSION));
            unsafe { BLK_BASE = base };
            return true;
        }
        false
    }

    fn setup(base: usize, ver: u32) {
        w(base, R_STATUS, 0);
        let mut st = S_ACK as u32;
        w(base, R_STATUS, st);
        st |= S_DRIVER as u32;
        w(base, R_STATUS, st);
        let q = &raw const QUEUE as u64;
        w(base, R_QUEUE_SEL, 0);
        let _ = r(base, R_QUEUE_NUM_MAX);
        w(base, R_QUEUE_NUM, QSIZE as u32);
        if ver == 1 {
            // legacy：单连续队列，QueuePFN 指向页帧
            w(base, R_HOST_FEAT_SEL, 0);
            let _ = r(base, R_HOST_FEAT);
            w(base, R_GUEST_FEAT_SEL, 0);
            w(base, R_GUEST_FEAT, 0);
            w(base, R_GUEST_PAGE_SIZE, 4096);
            w(base, R_QUEUE_ALIGN, 4096);
            w(base, R_QUEUE_PFN, (q >> 12) as u32);
        } else {
            // modern：协商 VERSION_1，分别给 desc/avail/used 地址
            w(base, R_GUEST_FEAT_SEL, 1);
            w(base, R_GUEST_FEAT, 1);
            w(base, R_GUEST_FEAT_SEL, 0);
            w(base, R_GUEST_FEAT, 0);
            st |= S_FEATURES_OK as u32;
            w(base, R_STATUS, st);
            let avail = q + (QSIZE * 16) as u64;
            let used = q + 4096;
            w(base, R_DESC_LOW, q as u32);
            w(base, R_DESC_HIGH, (q >> 32) as u32);
            w(base, R_DRIVER_LOW, avail as u32);
            w(base, R_DRIVER_HIGH, (avail >> 32) as u32);
            w(base, R_DEVICE_LOW, used as u32);
            w(base, R_DEVICE_HIGH, (used >> 32) as u32);
            w(base, R_QUEUE_READY, 1);
        }
        st |= S_DRIVER_OK as u32;
        w(base, R_STATUS, st);
    }

    pub fn notify() {
        w(unsafe { BLK_BASE }, R_QUEUE_NOTIFY, 0);
    }
}

