//! 单进程内存回环网络（loopback）：满足 libc-test socket，并为网络档（iperf/netperf
//! 回环）打底。UDP 按端口投递数据报，TCP connect→listener backlog→accept 配对。
//! 不涉硬件，全在内存，与执行模型解耦。
use alloc::vec::Vec;

pub struct Socket {
    pub port: u16,
    pub listening: bool,
    pub cloexec: bool,
    pub nonblock: bool,
    dgrams: Vec<Vec<u8>>, // UDP 收包队列
    backlog: Vec<usize>,  // TCP 待 accept 的对端 socket 下标
}

static mut SOCKETS: Vec<Socket> = Vec::new();
static mut NEXT_PORT: u16 = 20000;

fn socks() -> &'static mut Vec<Socket> {
    unsafe { &mut *(&raw mut SOCKETS) }
}

/// 每个程序启动前清空（与 fs::reset 同步调用）。
pub fn reset() {
    socks().clear();
    unsafe { NEXT_PORT = 20000 };
}

fn parse_port(addr: usize) -> u16 {
    // sockaddr_in.sin_port @+2，网络序（大端）
    let hi = unsafe { *((addr + 2) as *const u8) };
    let lo = unsafe { *((addr + 3) as *const u8) };
    ((hi as u16) << 8) | (lo as u16)
}

/// socket(domain, type, protocol)：type 低位 1=STREAM 2=DGRAM，高位有 SOCK_CLOEXEC。
pub fn socket(ty: usize) -> isize {
    socks().push(Socket {
        port: 0,
        listening: false,
        cloexec: ty & 0o2_000_000 != 0, // SOCK_CLOEXEC
        nonblock: ty & 0o4_000 != 0,    // SOCK_NONBLOCK
        dgrams: Vec::new(),
        backlog: Vec::new(),
    });
    crate::fs::install_socket(socks().len() - 1)
}

pub fn cloexec(sidx: usize) -> bool {
    sidx < socks().len() && socks()[sidx].cloexec
}

pub fn nonblock(sidx: usize) -> bool {
    sidx < socks().len() && socks()[sidx].nonblock
}

pub fn bind(fd: usize, addr: usize) -> isize {
    let sidx = match crate::fs::socket_of(fd) {
        Some(i) => i,
        None => return -9,
    };
    let mut port = parse_port(addr);
    if port == 0 {
        port = unsafe {
            let p = NEXT_PORT;
            NEXT_PORT += 1;
            p
        };
    }
    socks()[sidx].port = port;
    0
}

pub fn getsockname(fd: usize, addr: usize) -> isize {
    let sidx = match crate::fs::socket_of(fd) {
        Some(i) => i,
        None => return -9,
    };
    let port = socks()[sidx].port;
    unsafe {
        *(addr as *mut u16) = 2; // AF_INET
        *((addr + 2) as *mut u8) = (port >> 8) as u8;
        *((addr + 3) as *mut u8) = (port & 0xff) as u8;
        *((addr + 4) as *mut u32) = 0x0100_007f; // 127.0.0.1（网络序字节 7f 00 00 01）
    }
    0
}

pub fn listen(fd: usize) -> isize {
    match crate::fs::socket_of(fd) {
        Some(i) => {
            socks()[i].listening = true;
            0
        }
        None => -9,
    }
}

pub fn connect(addr: usize) -> isize {
    let port = parse_port(addr);
    match socks().iter().position(|s| s.listening && s.port == port) {
        Some(li) => {
            socks().push(Socket {
                port,
                listening: false,
                cloexec: false,
                nonblock: false,
                dgrams: Vec::new(),
                backlog: Vec::new(),
            });
            let pidx = socks().len() - 1;
            socks()[li].backlog.push(pidx);
            0
        }
        None => -111, // ECONNREFUSED
    }
}

pub fn accept(fd: usize) -> isize {
    let sidx = match crate::fs::socket_of(fd) {
        Some(i) => i,
        None => return -9,
    };
    if socks()[sidx].backlog.is_empty() {
        return -11; // EAGAIN
    }
    let pidx = socks()[sidx].backlog.remove(0);
    crate::fs::install_socket(pidx)
}

pub fn sendto(buf: usize, len: usize, addr: usize) -> isize {
    let port = parse_port(addr);
    match socks().iter().position(|s| s.port == port) {
        Some(ti) => {
            let mut d = Vec::with_capacity(len);
            for i in 0..len {
                d.push(unsafe { *((buf + i) as *const u8) });
            }
            socks()[ti].dgrams.push(d);
            len as isize
        }
        None => -1,
    }
}

pub fn recvfrom(fd: usize, buf: usize, len: usize) -> isize {
    let sidx = match crate::fs::socket_of(fd) {
        Some(i) => i,
        None => return -9,
    };
    if socks()[sidx].dgrams.is_empty() {
        return -11; // EAGAIN（设了 SO_RCVTIMEO，同步模型下数据报已先到）
    }
    let d = socks()[sidx].dgrams.remove(0);
    let n = core::cmp::min(len, d.len());
    for (i, &byte) in d.iter().take(n).enumerate() {
        unsafe { *((buf + i) as *mut u8) = byte };
    }
    n as isize
}

