// 每个用户程序的运行超时（10 MHz：~3 秒）+ 定时器周期（~0.2 秒）。
const TIMEOUT_TICKS: u64 = 30_000_000;
const TICK_INTERVAL: u64 = 2_000_000;

static mut DEADLINE: u64 = u64::MAX;

fn rdtime() -> u64 {
