// ===== la64 分页：4 级 4KB 页，软件填 TLB =====
#[repr(C, align(4096))]
struct PageTable([u64; 512]);
static mut ROOT: PageTable = PageTable([0; 512]);

const RAM_END: usize = 0x1000_0000; // 恒等映射上界（内核 + 栈 + 帧区，256 MiB）
static FRAME_NEXT: AtomicUsize = AtomicUsize::new(0);
// 内核页表帧水位（init_paging 结束时记下）：reset_user_space 把 FRAME_NEXT 退回此处，
// 复用全部用户帧、保留内核映射。
static KERNEL_WATERMARK: AtomicUsize = AtomicUsize::new(0);
// 用户地址空间布局（均 ≥ 2 GiB，避开内核 Dir2[0] / PCI Dir2[1]）。
static mut USER_BRK: usize = 0;
static mut MMAP_NEXT: usize = 0x2_0000_0000; // mmap 区从 8 GiB 起向上
const USTACK_TOP: usize = 0x1_8000_0000; // 用户栈顶 6 GiB（向下生长）

// la64 PTE/TLBRELO 位
const PTE_V: u64 = 1 << 0; // valid
const PTE_D: u64 = 1 << 1; // dirty
const PTE_MAT_CC: u64 = 1 << 4; // coherent cached（RAM）
const PTE_MAT_SUC: u64 = 0 << 4; // strongly-ordered uncached（MMIO）
const PTE_G: u64 = 1 << 6; // global
const PTE_KERN_RAM: u64 = PTE_V | PTE_D | PTE_MAT_CC | PTE_G;
const PTE_KERN_MMIO: u64 = PTE_V | PTE_D | PTE_MAT_SUC | PTE_G;

fn frame_alloc() -> usize {
    let pa = FRAME_NEXT.fetch_add(4096, Ordering::Relaxed);
    unsafe { core::ptr::write_bytes(pa as *mut u8, 0, 4096) };
    pa
}

// va→pa 4KB 映射。4 级：Dir3[47:39]→Dir2[38:30]→Dir1[29:21]→PT[20:12]。
// 中间目录项 = 下级表物理地址；叶 PTE = pa | flags。
fn map_page(va: usize, pa: usize, leaf: u64) {
    let idx = [
        (va >> 39) & 0x1ff,
        (va >> 30) & 0x1ff,
        (va >> 21) & 0x1ff,
        (va >> 12) & 0x1ff,
    ];
    let mut table = &raw mut ROOT as *mut u64;
    for &i in &idx[..3] {
        let e = unsafe { &mut *table.add(i) };
        if *e == 0 {
            *e = frame_alloc() as u64;
        }
        table = (*e & !0xfff) as *mut u64;
    }
    unsafe { *table.add(idx[3]) = (pa as u64 & !0xfff) | leaf };
}

// TLB refill 处理器（独立异常向量 TLBRENTRY，4KB 对齐）：PGD→lddir×3→ldpte×2→tlbfill→ertn。
global_asm!(
    ".section .text",
    ".balign 4096",
    ".globl __la_tlb_refill",
    "__la_tlb_refill:",
    "    csrwr $t0, 0x8b", // TLBRSAVE：存 t0
    "    csrrd $t0, 0x1b", // PGD：页表根（对应坏地址）
    "    lddir $t0, $t0, 3",
    "    beqz  $t0, 1f",
    "    lddir $t0, $t0, 2",
    "    beqz  $t0, 1f",
    "    lddir $t0, $t0, 1",
    "    beqz  $t0, 1f",
    "    ldpte $t0, 0",
    "    ldpte $t0, 1",
    "    b     2f",
    "1:",                  // 无效项：填一个 NR|NX 的占位（4KB）
    "    csrrd $t0, 0x8e", // TLBREHI
    "    ori   $t0, $t0, 0xc",
    "    csrwr $t0, 0x8e",
    "    rotri.d $t0, $t0, 61",
    "    ori   $t0, $t0, 3",
    "    rotri.d $t0, $t0, 3",
    "    csrwr $t0, 0x8c", // TLBRELO0
    "    csrrd $t0, 0x8c",
    "    csrwr $t0, 0x8d", // TLBRELO1
    "2:",
    "    tlbfill",
    "    csrrd $t0, 0x8b", // 复 t0
    "    ertn",
);

/// 启用 4 级分页（恒等映射低 RAM + MMIO），软件填 TLB。启用后 UART 仍可打印则成功。
pub fn init_paging() {
    unsafe extern "C" {
        static _ekernel: u8;
        fn __la_tlb_refill();
    }
    FRAME_NEXT.store(
        ((&raw const _ekernel as usize) + 4095) & !4095,
        Ordering::Relaxed,
    );
    // 恒等映射低 RAM（内核 + 栈 + 帧区）
    let mut va = 0usize;
    while va < RAM_END {
        map_page(va, va, PTE_KERN_RAM);
        va += 4096;
    }
    // 恒等映射 MMIO（UART 0x1fe001e0 / GED 0x100e001c）uncached
    map_page(0x1fe0_0000, 0x1fe0_0000, PTE_KERN_MMIO);
    map_page(0x100e_0000, 0x100e_0000, PTE_KERN_MMIO);
    // PCIe ECAM bus 0（32 dev × 8 fn × 4 KiB = 1 MiB）配置空间，uncached
    let mut e = 0x2000_0000usize;
    while e < 0x2010_0000 {
        map_page(e, e, PTE_KERN_MMIO);
        e += 4096;
    }
    // PCI MMIO BAR 窗（0x40000000 起 16 MiB），uncached
    let mut b = 0x4000_0000usize;
    while b < 0x4100_0000 {
        map_page(b, b, PTE_KERN_MMIO);
        b += 4096;
    }
    unsafe {
        let root = &raw const ROOT as usize;
        let pwcl = 12usize | (9 << 5) | (21 << 10) | (9 << 15) | (30 << 20) | (9 << 25);
        let pwch = 39usize | (9 << 6);
        asm!("csrwr {0}, 0x1c", inout(reg) pwcl => _); // PWCL
        asm!("csrwr {0}, 0x1d", inout(reg) pwch => _); // PWCH
        asm!("csrwr {0}, 0x19", inout(reg) root => _); // PGDL = root
        asm!("csrwr {0}, 0x1e", inout(reg) 12usize => _); // STLBPS = 12 (4KB)
        asm!("csrwr {0}, 0x88", inout(reg) __la_tlb_refill as *const () as usize => _); // TLBRENTRY
        asm!("invtlb 0x0, $r0, $r0"); // 清全部 TLB
        // EUEN：启用 FPE(bit0)/SXE(bit1 LSX)/ASXE(bit2 LASX)——硬浮点 ABI 程序需要，
        // 否则用户态 FP 指令触发 FPD(ecode 0xf) 异常。
        asm!("csrwr {0}, 0x2", inout(reg) 0b111usize => _);
        // CRMD：清 DA(bit3)、置 PG(bit4) → 切到映射地址翻译
        let mut crmd: usize;
        asm!("csrrd {}, 0x0", out(reg) crmd);
        crmd = (crmd & !(1 << 3)) | (1 << 4);
        asm!("csrwr {0}, 0x0", inout(reg) crmd => _);
    }
    KERNEL_WATERMARK.store(FRAME_NEXT.load(Ordering::Relaxed), Ordering::Relaxed);
}

