/// 清空用户地址空间：抹掉 Dir2[2..512]（≥ 2 GiB 全部用户映射），帧水位退回内核水印。
/// 内核 Dir2[0]（0–1 GiB）与 PCI Dir2[1]（1–2 GiB）保留。
pub fn reset_user_space() {
    let dir3 = &raw mut ROOT as *mut u64;
    let dir2_entry = unsafe { *dir3 };
    if dir2_entry != 0 {
        let dir2 = (dir2_entry & !0xfff) as *mut u64;
        for i in 2..512 {
            unsafe { *dir2.add(i) = 0 };
        }
    }
    FRAME_NEXT.store(KERNEL_WATERMARK.load(Ordering::Relaxed), Ordering::Relaxed);
    unsafe {
        MMAP_NEXT = 0x2_0000_0000;
        asm!("invtlb 0x0, $r0, $r0");
    }
}

