/// brk(addr)：addr==0 查询当前；否则增长到 addr（按页映射新增区），返回新 brk。
pub fn user_brk(addr: usize) -> usize {
    unsafe {
        if addr == 0 || addr < USER_BRK {
            return USER_BRK;
        }
        let mut va = (USER_BRK + 0xfff) & !0xfff;
        let end = (addr + 0xfff) & !0xfff;
        while va < end {
            map_page(va, frame_alloc(), PTE_USER);
            va += 4096;
        }
        asm!("invtlb 0x0, $r0, $r0");
        USER_BRK = addr;
        USER_BRK
    }
}

/// 匿名 mmap：分配 len 字节用户页，返回起始 VA。
pub fn user_mmap(len: usize) -> usize {
    unsafe {
        let base = MMAP_NEXT;
        let pages = len.div_ceil(4096);
        for p in 0..pages {
            map_page(base + p * 4096, frame_alloc(), PTE_USER);
        }
        MMAP_NEXT += pages * 4096;
        asm!("invtlb 0x0, $r0, $r0");
        base
    }
}

