    regs: [usize; 12],
}
static mut CURRENT_CTX: *mut KernelContext = core::ptr::null_mut();

global_asm!(
    ".section .text",
    ".globl __la_run_user",
    "__la_run_user:", // a0=ctx, a1=entry, a2=user_sp, a3=kstack_top
    "    st.d $r1, $a0, 0",
    "    st.d $r3, $a0, 8",
    "    st.d $r22, $a0, 2*8",
    "    st.d $r23, $a0, 3*8",
    "    st.d $r24, $a0, 4*8",
    "    st.d $r25, $a0, 5*8",
    "    st.d $r26, $a0, 6*8",
    "    st.d $r27, $a0, 7*8",
    "    st.d $r28, $a0, 8*8",
    "    st.d $r29, $a0, 9*8",
    "    st.d $r30, $a0, 10*8",

    "    st.d $r30, $a0, 10*8",
    "    st.d $r31, $a0, 11*8",
    "    la.local $t0, __la_uentry",
    "    csrwr $t0, 0xc",    // EENTRY = 用户陷入入口
