fn sys_wait4(pid: usize, status: usize) -> isize {
    unsafe {
        let z = &mut *(&raw mut ZOMBIES);
        if NZOMBIE == 0 {
            return -10; // ECHILD
        }
        let want = pid as isize;
        let mut found = None;
        for i in (0..NZOMBIE).rev() {
            if want == -1 || z[i].0 == pid {
                found = Some(i);
                break;
            }
        }
        let i = match found {
            Some(i) => i,
            None => return -10,
        };
        let (cpid, code) = z[i];
        for j in i..NZOMBIE - 1 {
            z[j] = z[j + 1];
        }
        NZOMBIE -= 1;
        if status != 0 {
            (status as *mut i32).write_volatile(((code & 0xff) << 8) as i32);
        }
        cpid as isize
    }
}

/// execve(path)：从磁盘载入新映像顶替当前进程；失败返回 -ENOENT。
fn sys_execve(path_ptr: usize) -> isize {
    let path = user_cstr(path_ptr);
    if let Some(elf) = crate::ext4::global().load(&path) {
        let (entry, sp) = khal::load_elf(&elf);
        khal::exec_replace(entry, sp);
    }
    -2
}

/// nanosleep：按请求时长忙等（rdtime 随真实时间推进），上限 2s 防极端等待。
fn sys_nanosleep(req: usize) -> isize {
    if req == 0 {
        return 0;
    }
    let sec = unsafe { (req as *const u64).read_volatile() };
    let nsec = unsafe { ((req + 8) as *const u64).read_volatile() };
    let mut total = sec.saturating_mul(1_000_000_000).saturating_add(nsec);
    if total > 2_000_000_000 {
        total = 2_000_000_000;
    }
    let start = khal::time_ns();
    while khal::time_ns().wrapping_sub(start) < total {
        core::hint::spin_loop();
    }
    0
}

fn sys_mmap(len: usize, flags: usize, fd: usize) -> isize {
    let va = khal::user_mmap(len);
    // 文件映射（非匿名且 fd 有效）：把文件内容拷进映射区。
    if flags & 0x20 == 0
        && fd as isize != -1
        && let Some(data) = crate::fs::file_bytes(fd)
    {
        let n = core::cmp::min(len, data.len());
        for (i, &byte) in data.iter().take(n).enumerate() {
            unsafe { ((va + i) as *mut u8).write_volatile(byte) };
        }
    }
    // MAP_SHARED(0x01)：标记为共享，fork 时不快照（子进程写入对父可见）。
    if flags & 0x01 != 0 {
        khal::mark_shared(va, va + len);
    }
    va as isize
}

