// 进程信号掩码（首 64 个信号，覆盖标准信号；siglongjmp 保存/恢复需要）。
static mut SIGMASK: u64 = 0;

fn sys_rt_sigprocmask(how: usize, set: usize, oldset: usize) -> isize {
    unsafe {
        if oldset != 0 {
            (oldset as *mut u64).write_volatile(SIGMASK);
        }
        if set != 0 {
            let s = (set as *const u64).read_volatile();
            SIGMASK = match how {
                0 => SIGMASK | s,  // SIG_BLOCK
                1 => SIGMASK & !s, // SIG_UNBLOCK
                2 => s,            // SIG_SETMASK
                _ => SIGMASK,
            };
        }
    }
    0
}

fn sys_fcntl(fd: usize, cmd: usize, arg: usize) -> isize {
    match cmd {
        0 | 1030 => crate::fs::dup(fd), // F_DUPFD / F_DUPFD_CLOEXEC
        1 => {
            // F_GETFD：socket 带 SOCK_CLOEXEC 时返回 FD_CLOEXEC
            match crate::fs::socket_of(fd) {
                Some(i) if crate::net::cloexec(i) => 1,
                _ => 0,
            }
        }
        3 => {
            // F_GETFL：socket 带 SOCK_NONBLOCK 时返回 O_NONBLOCK
            match crate::fs::socket_of(fd) {
                Some(i) if crate::net::nonblock(i) => 0x800,
                _ => 0,
            }
        }
        _ => {
            let _ = arg;
            0 // F_SETFD/SETFL：当作成功
        }
    }
}

/// getrlimit/setrlimit/prlimit64：仅 RLIMIT_NOFILE(7) 真处理（影响 fd 上限），其余给大值。
fn sys_prlimit(resource: usize, new: usize, old: usize) -> isize {
    if resource == 7 {
        if old != 0 {
            let cur = crate::fs::get_nofile() as u64;
            unsafe {
                (old as *mut u64).write_volatile(cur);
                ((old + 8) as *mut u64).write_volatile(cur);
            }
        }
        if new != 0 {
            let cur = unsafe { (new as *const u64).read_volatile() };
            crate::fs::set_nofile(cur as usize);
        }
    } else if old != 0 {
        unsafe {
            (old as *mut u64).write_volatile(1 << 30);
            ((old + 8) as *mut u64).write_volatile(1 << 30);
        }
    }
    0
}

