fn sys_getrandom(buf: usize, len: usize) -> isize {
    // 用 time CSR 做种子的简单 LCG（够过随机性自检，非密码学）。
    let mut x = khal::time_ns() ^ 0x9e37_79b9_7f4a_7c15;
    for i in 0..len {
        x = x
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        unsafe { ((buf + i) as *mut u8).write_volatile((x >> 33) as u8) };
    }
    len as isize
}

fn sys_clock_gettime(ts: usize) -> isize {
    let ns = khal::time_ns();
    unsafe {
        (ts as *mut u64).write_volatile(ns / 1_000_000_000);
        ((ts + 8) as *mut u64).write_volatile(ns % 1_000_000_000);
    }
    0
}

fn sys_gettimeofday(tv: usize) -> isize {
    let ns = khal::time_ns();
    unsafe {
        (tv as *mut u64).write_volatile(ns / 1_000_000_000);
        ((tv + 8) as *mut u64).write_volatile((ns % 1_000_000_000) / 1000);
    }
    0
}

fn sys_times(buf: usize) -> isize {
    let t = (khal::time_ns() / 100) as u64;
    for i in 0..4 {
        unsafe { ((buf + i * 8) as *mut u64).write_volatile(t) };
    }
    t as isize
}

