/// 取文件内容（文件映射 mmap 用）。
pub fn file_bytes(fd: usize) -> Option<&'static [u8]> {
    if fd >= MAXFD {
        return None;
    }
    if let Some(Fd::File { idx, .. }) = &fds()[fd] {
        Some(files()[*idx].data.as_slice())
    } else {
        None
    }
}

/// lseek(fd, offset, whence)：移动普通文件读写位置，返回新位置。
pub fn lseek(fd: usize, offset: isize, whence: usize) -> isize {
    if fd >= MAXFD {
        return -9;
    }
    match &mut fds()[fd] {
        Some(Fd::File { idx, pos }) => {
            let base = match whence {
                0 => 0,                                 // SEEK_SET
                1 => *pos as isize,                     // SEEK_CUR
                2 => files()[*idx].data.len() as isize, // SEEK_END
                _ => return -22,
            };
            let np = base + offset;
            if np < 0 {
                return -22;
            }
            *pos = np as usize;
            np
        }
        _ => -29, // ESPIPE：console / pipe 不可 seek
    }
}

/// ftruncate(fd, len)：把普通文件大小设为 len（扩展补零）。
pub fn ftruncate(fd: usize, len: usize) -> isize {
    if fd < MAXFD
        && let Some(Fd::File { idx, .. }) = &fds()[fd]
    {
        files()[*idx].data.resize(len, 0);
        0
    } else {
        -9
    }
}

/// 按路径 stat（fstatat 用）：打开→fstat→关闭。
pub fn stat_path(path: &str, buf: usize) -> isize {
    let fd = openat(path, 0);
    if fd < 0 {
        return fd;
    }
    let r = fstat(fd as usize, buf);
    close(fd as usize);
    r
}

/// statx(dirfd, path, flags, mask, buf)：空路径走 dirfd（AT_EMPTY_PATH = fstat 语义），
/// 否则解析路径。填 struct statx（mode@0x1c / size@0x28 等，与 stat 布局不同）。
pub fn statx(dirfd: usize, path: &str, buf: usize) -> isize {
    let attrs = if path.is_empty() {
        fd_attrs(dirfd)
    } else {
        let fd = openat(path, 0);
        if fd < 0 {
            return fd;
        }
        let a = fd_attrs(fd as usize);
        close(fd as usize);
        a
    };
    let (mode, size, atime, mtime) = match attrs {
        Some(a) => a,
        None => return -9,
    };
    unsafe {
        core::ptr::write_bytes(buf as *mut u8, 0, 256);
        ((buf) as *mut u32).write_volatile(0x0000_07ff); // stx_mask（基本字段全有效）
        ((buf + 0x04) as *mut u32).write_volatile(512); // stx_blksize
        ((buf + 0x10) as *mut u32).write_volatile(1); // stx_nlink
        ((buf + 0x1c) as *mut u16).write_volatile(mode as u16); // stx_mode
        ((buf + 0x28) as *mut u64).write_volatile(size); // stx_size
        ((buf + 0x30) as *mut u64).write_volatile(size.div_ceil(512)); // stx_blocks
        ((buf + 0x40) as *mut u64).write_volatile(atime); // stx_atime.tv_sec
        ((buf + 0x70) as *mut u64).write_volatile(mtime); // stx_mtime.tv_sec
    }
    0
}

/// fd 的 (mode, size, atime, mtime)：文件取节点信息，控制台/null/zero 作字符设备。
fn fd_attrs(fd: usize) -> Option<(u32, u64, u64, u64)> {
    if fd >= MAXFD {
        return None;
    }
    if let Some(Fd::File { idx, .. }) = &fds()[fd] {
        let n = &files()[*idx];
        let mode = if n.dir { 0o040755u32 } else { 0o100644u32 };
        let size = if n.dir { 4096 } else { n.data.len() as u64 };
        Some((mode, size, n.atime, n.mtime))
    } else if matches!(
        &fds()[fd],
        Some(Fd::Console) | Some(Fd::Null) | Some(Fd::Zero)
    ) {
        Some((0o020666u32, 0, 0, 0)) // 字符设备
    } else {
        None
    }
}

pub fn fstat(fd: usize, buf: usize) -> isize {
    let (mode, size, atime, mtime) = match fd_attrs(fd) {
        Some(a) => a,
        None => return -9,
    };
    unsafe {
        core::ptr::write_bytes(buf as *mut u8, 0, 128);
        ((buf + 16) as *mut u32).write_volatile(mode);
        ((buf + 20) as *mut u32).write_volatile(1);
        ((buf + 48) as *mut u64).write_volatile(size);
        ((buf + 56) as *mut u32).write_volatile(512);
        ((buf + 64) as *mut u64).write_volatile(size.div_ceil(512));
        ((buf + 72) as *mut u64).write_volatile(atime); // st_atim.tv_sec
        ((buf + 88) as *mut u64).write_volatile(mtime); // st_mtim.tv_sec
    }
    0
}

/// utimensat（按路径）：设文件 atime/mtime。
pub fn utimens(path: &str, times: usize) -> isize {
    let name = path.trim_start_matches("./").trim_start_matches('/');
    match node_idx(name, false) {
        Some(i) => set_times(i, times),
        None => -2,
    }
}

/// futimens（按 fd）：path 为 NULL 时用 dirfd 作为文件描述符。
pub fn utimens_fd(fd: usize, times: usize) -> isize {
    if fd < MAXFD
        && let Some(Fd::File { idx, .. }) = &fds()[fd]
    {
        set_times(*idx, times)
    } else {
        -9
    }
}

fn set_times(idx: usize, times: usize) -> isize {
    let now = khal::time_ns() / 1_000_000_000;
    const UTIME_NOW: u64 = 0x3fff_ffff;
    const UTIME_OMIT: u64 = 0x3fff_fffe;
    let (mut at, mut mt) = (now, now);
    if times != 0 {
        let asec = unsafe { (times as *const u64).read_volatile() };
        let ansec = unsafe { ((times + 8) as *const u64).read_volatile() };
        let msec = unsafe { ((times + 16) as *const u64).read_volatile() };
        let mnsec = unsafe { ((times + 24) as *const u64).read_volatile() };
        at = if ansec == UTIME_NOW { now } else { asec };
        mt = if mnsec == UTIME_NOW { now } else { msec };
        let n = &mut files()[idx];
        if ansec != UTIME_OMIT {
            n.atime = at;
        }
        if mnsec != UTIME_OMIT {
            n.mtime = mt;
        }
        return 0;
    }
    let n = &mut files()[idx];
    n.atime = at;
    n.mtime = mt;
    0
}

pub fn getdents64(fd: usize, buf: usize, len: usize) -> isize {
    if fd >= MAXFD {
        return -9;
    }
    if let Some(Fd::File { idx, pos }) = &mut fds()[fd] {
        let names = files()[*idx].names.clone();
        let mut written = 0usize;
        while *pos < names.len() {
            let nb = names[*pos].as_bytes();
            let reclen = (19 + nb.len() + 1 + 7) & !7;
            if written + reclen > len {
                break;
            }
            let p = buf + written;
            unsafe {
                (p as *mut u64).write_volatile(*pos as u64 + 1);
                ((p + 8) as *mut u64).write_volatile(reclen as u64);
                ((p + 16) as *mut u16).write_volatile(reclen as u16);
                *((p + 18) as *mut u8) = 8; // DT_REG
                for (i, &c) in nb.iter().enumerate() {
                    *((p + 19 + i) as *mut u8) = c;
                }
                *((p + 19 + nb.len()) as *mut u8) = 0;
            }
            written += reclen;
            *pos += 1;
        }
        written as isize
    } else {
        -9
    }
}

fn dup_fd(from: usize, to: Option<usize>) -> isize {
    if from >= MAXFD {
        return -9;
    }
    let cloned = match &fds()[from] {
        Some(f) => f.clone(),
        None => return -9,
    };
    let nfd = match to {
        Some(n) if n < MAXFD => n,
        Some(_) => return -9,
        None => match alloc_fd() {
            Some(n) => n,
            None => return -24,
        },
    };
    fds()[nfd] = Some(cloned);
    nfd as isize
}

pub fn dup(fd: usize) -> isize {
    dup_fd(fd, None)
}
pub fn dup3(oldfd: usize, newfd: usize) -> isize {
    dup_fd(oldfd, Some(newfd))
}
